concept.syntax:
class Person(val name: String, var age: Int) {
    // member function
    fun greet() = "Hi, I'm $name!"

    // computed property (no backing field)
    val isAdult: Boolean
        get() = age >= 18
}

// Create an instance
val p = Person("Alice", 30)
println(p.greet())   // Hi, I'm Alice!
p.age = 31           // OK — var property
// p.name = "Bob"   // ERROR — val property

demo.code:
class Person(val name: String, var age: Int) {
    fun greet(): String = "Hi, I'm $name and I'm $age."
    fun birthday() { age++ }
}

fun main() {
    val p = Person("Alice", 30)
    println(p.greet())
    p.birthday()
    println(p.age)
}

